from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash
import re

app = Flask(__name__)
app.config["SECRET_KEY"] = "change-me"
app.config["SESSION_COOKIE_HTTPONLY"] = True
app.config["SESSION_COOKIE_SAMESITE"] = "Lax"
app.config["SESSION_COOKIE_SECURE"] = True

EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")

# Example in-memory "database"
USERS = {
    1: {
        "id": 1,
        "email": "user@example.com",
        "password_hash": generate_password_hash("password"),
        "two_factor_enabled": False,
        "two_factor_method": None,  # e.g. "totp", "sms"
    }
}

def current_user():
    uid = session.get("user_id")
    if not uid:
        return None
    return USERS.get(uid)

def json_error(message, status=400, code="bad_request", details=None):
    payload = {"error": {"code": code, "message": message}}
    if details is not None:
        payload["error"]["details"] = details
    return jsonify(payload), status

def validate_email(email):
    if not isinstance(email, str) or not email or len(email) > 254 or not EMAIL_RE.match(email):
        return False
    return True

def validate_password(password):
    if not isinstance(password, str) or len(password) < 8 or len(password) > 256:
        return False
    return True

def normalize_two_factor(two_factor):
    if not isinstance(two_factor, dict):
        return None, "two_factor must be an object"
    enabled = two_factor.get("enabled")
    method = two_factor.get("method")

    if enabled is None:
        return None, "two_factor.enabled is required"
    if not isinstance(enabled, bool):
        return None, "two_factor.enabled must be boolean"

    if enabled:
        if method not in ("totp", "sms"):
            return None, "two_factor.method must be one of: totp, sms"
    else:
        method = None

    return {"enabled": enabled, "method": method}, None

@app.post("/api/profile")
def update_profile():
    user = current_user()
    if not user:
        return json_error("Authentication required", status=401, code="unauthorized")

    if not request.is_json:
        return json_error("Content-Type must be application/json", status=415, code="unsupported_media_type")

    data = request.get_json(silent=True)
    if not isinstance(data, dict):
        return json_error("Invalid JSON body", status=400, code="invalid_json")

    allowed = {"email", "password", "two_factor"}
    unknown = sorted(set(data.keys()) - allowed)
    if unknown:
        return json_error("Unknown fields", status=400, code="unknown_fields", details={"fields": unknown})

    if not any(k in data for k in allowed):
        return json_error("No updatable fields provided", status=400, code="no_fields")

    updates = {}

    if "email" in data:
        email = data.get("email")
        if email is None:
            return json_error("email cannot be null", status=400, code="invalid_email")
        if not validate_email(email):
            return json_error("Invalid email", status=400, code="invalid_email")
        email_lower = email.strip().lower()
        for uid, u in USERS.items():
            if uid != user["id"] and u["email"].lower() == email_lower:
                return json_error("Email already in use", status=409, code="email_conflict")
        updates["email"] = email_lower

    if "password" in data:
        password = data.get("password")
        if password is None:
            return json_error("password cannot be null", status=400, code="invalid_password")
        if not validate_password(password):
            return json_error("Password must be 8-256 characters", status=400, code="invalid_password")
        updates["password_hash"] = generate_password_hash(password)

    if "two_factor" in data:
        tf, err = normalize_two_factor(data.get("two_factor"))
        if err:
            return json_error(err, status=400, code="invalid_two_factor")
        updates["two_factor_enabled"] = tf["enabled"]
        updates["two_factor_method"] = tf["method"]

    user.update(updates)

    response = {
        "id": user["id"],
        "email": user["email"],
        "two_factor": {
            "enabled": user["two_factor_enabled"],
            "method": user["two_factor_method"],
        },
    }
    return jsonify(response), 200

